import os
import re
import json
import time
import traceback
from functools import wraps




def handle_response(afunc):
    @wraps(afunc)
    def _(*args, **kwargs):
        try:
            reply = afunc(*args, **kwargs)
            if reply is not None:
                if reply is True:
                    return "--PASS--"
                elif reply is False:
                    return "--FAIL--"
                elif reply == "done":
                    return "--PASS--"
                else:
                    if type(reply) is str and len(reply) == 0:
                        return "--FAIL--"
                    else:
                        return reply
            else:
                return "--FAIL--"
        except Exception as e:
            print(e.message, os.linesep, traceback.format_exc())
            info = re.sub('\r|\n', ',', e.message)
            return "--FAIL--{}".format(info)
    return _


def public(rpc_name=None):
    def wrapper(afunc):
        afunc._rpc_public_name = rpc_name or afunc.__name__

        @wraps(afunc)
        def _(*args, **kwargs):
            try:
                reply = afunc(*args, **kwargs)
                if reply is None:
                    return "--FAIL--"
                if reply is True:
                    return "--PASS--"
                elif reply is False:
                    return "--FAIL--"
                elif reply == "done":
                    return "--PASS--"
                else:
                    if type(reply) is str and len(reply) == 0:
                        return "--FAIL--"
                    else:
                        return reply
            except Exception as e:
                print(e.message, os.linesep, traceback.format_exc())
                return "--FAIL--{}".format(e.message)
        return _
    return wrapper


def retry_with_delay(max_retries=3, delay_seconds=0.5):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            retries = 0
            result = False
            while retries < max_retries:
                try:
                    result = func(*args, **kwargs)
                    if result:
                        return result
                    else:
                        retries += 1
                        print(f"Result is False, retry:{retries}")
                except Exception as e:
                    retries += 1
                    print(f"An error occurred: {e},retry:{retries}")
                time.sleep(delay_seconds)
            return result  # Return the last result, even if it's not expected
        return wrapper
    return decorator

class Unit(object):
    unit_exponents = {
        "uV": -6,'mV': -3,"V": 0,
        "nA": -9,"uA": -6,'mA': -3,"A": 0,
        'mOhm': -3,"Ohm": 0,"kOhm": 3,"MOhm": 6,
        "nS": -9,"uS": -6,"mS": -3,"S": 0,
        'mVpp': -3,'Vpp': 0,
        'mVrms': -3,'Vrms': 0
    }

    @staticmethod
    def convert_unit(value, from_unit, to_unit):
        if not from_unit or not to_unit:
            return False, "Units are not specified but are required."
        from_u = Unit.unit_exponents.get(from_unit)
        to_u = Unit.unit_exponents.get(to_unit)
        return float(value) * pow(10, (from_u - to_u))


def singleton(cls):
    _instance = {}

    def _singleton(*args, **kwargs):
        if cls not in _instance:
            _instance[cls] = cls(*args, **kwargs)
        return _instance[cls]

    return _singleton


